import React, { useState } from 'react';
import axios from 'axios';

const CITIES = [
  'Quezon City', 'Makati', 'Manila', 'Pasig', 'Taguig', 'Mandaluyong', 'Paranaque',
  'Las Pinas', 'Muntinlupa', 'Caloocan', 'Marikina', 'Valenzuela', 'Pasay',
  'Cavite City', 'Bacoor', 'Imus', 'Dasmariñas', 'General Trias', 'Tagaytay',
  'Antipolo', 'Cainta', 'Taytay', 'San Mateo', 'Meycauayan', 'Malolos',
  'Calamba', 'Santa Rosa', 'Biñan', 'San Pedro', 'Lipa', 'Batangas City',
  'San Fernando', 'Angeles', 'Mabalacat', 'Olongapo',
  'Cebu City', 'Mandaue', 'Lapu-Lapu', 'Davao City', 'Other',
];

const PROVINCES = [
  'Metro Manila', 'Cavite', 'Rizal', 'Laguna', 'Batangas', 'Bulacan', 'Pampanga',
  'Zambales', 'Cebu', 'Davao del Sur', 'Iloilo', 'La Union', 'Pangasinan',
  'Benguet', 'Palawan', 'Quezon Province', 'Albay', 'Camarines Sur',
  'Leyte', 'South Cotabato', 'Other',
];

const REGIONS = [
  'NCR', 'Region I', 'Region II', 'Region III', 'Region IV-A', 'Region IV-B',
  'Region V', 'Region VI', 'Region VII', 'Region VIII', 'Region IX', 'Region X',
  'Region XI', 'Region XII', 'Region XIII', 'CAR', 'BARMM',
];

const InputField = ({ label, required, error, children }) => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
    <label style={{
      fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)',
      textTransform: 'uppercase', letterSpacing: '0.08em',
    }}>
      {label} {required && <span style={{ color: 'var(--gold)' }}>*</span>}
    </label>
    {children}
    {error && <span style={{ fontSize: 12, color: 'var(--error)' }}>{error}</span>}
  </div>
);

const inputStyle = (hasError) => ({
  background: 'rgba(255,255,255,0.04)',
  border: `1px solid ${hasError ? 'var(--error)' : 'var(--border-subtle)'}`,
  borderRadius: 10,
  color: 'var(--text-primary)',
  padding: '12px 16px',
  fontSize: 15,
  outline: 'none',
  transition: 'border-color 0.2s, background 0.2s',
  width: '100%',
});

function formatPHP(num) {
  if (!num) return '—';
  if (num >= 1_000_000) return `₱${(num / 1_000_000).toFixed(2)}M`;
  if (num >= 1_000) return `₱${(num / 1_000).toFixed(0)}K`;
  return `₱${num.toLocaleString()}`;
}

export default function PredictPage() {
  const [form, setForm] = useState({
    city: '', province: '', region: '',
    floor_area: '', land_area: '', bedrooms: '', bathrooms: '',
  });
  const [errors, setErrors] = useState({});
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState('');

  const update = (field, val) => {
    setForm(f => ({ ...f, [field]: val }));
    setErrors(e => ({ ...e, [field]: '' }));
    setApiError('');
  };

  const validate = () => {
    const e = {};
    if (!form.city) e.city = 'City is required';
    if (!form.province) e.province = 'Province is required';
    if (!form.region) e.region = 'Region is required';
    if (!form.floor_area || isNaN(form.floor_area) || Number(form.floor_area) <= 0)
      e.floor_area = 'Enter a valid floor area (sqm)';
    if (form.land_area && (isNaN(form.land_area) || Number(form.land_area) <= 0))
      e.land_area = 'Enter a valid land area';
    if (!form.bedrooms || isNaN(form.bedrooms) || Number(form.bedrooms) < 1)
      e.bedrooms = 'Enter number of bedrooms (min 1)';
    if (!form.bathrooms || isNaN(form.bathrooms) || Number(form.bathrooms) < 1)
      e.bathrooms = 'Enter number of bathrooms (min 1)';
    return e;
  };

  const handleSubmit = async () => {
    const e = validate();
    if (Object.keys(e).length > 0) { setErrors(e); return; }
    setLoading(true);
    setResult(null);
    setApiError('');
    try {
      const res = await axios.post('/api/predict', {
        ...form,
        floor_area: Number(form.floor_area),
        land_area: form.land_area ? Number(form.land_area) : null,
        bedrooms: Number(form.bedrooms),
        bathrooms: Number(form.bathrooms),
      });
      setResult(res.data);
    } catch (err) {
      setApiError(err.response?.data?.error || 'Failed to connect to the server. Is the Flask backend running?');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setForm({ city: '', province: '', region: '', floor_area: '', land_area: '', bedrooms: '', bathrooms: '' });
    setErrors({}); setResult(null); setApiError('');
  };

  return (
    <div style={{ maxWidth: 1100, margin: '0 auto', padding: '60px 24px' }}>
      {/* Header */}
      <div style={{ marginBottom: 48, animation: 'fadeUp 0.5s ease' }}>
        <h1 style={{ fontSize: 'clamp(28px, 4vw, 48px)', fontWeight: 800, marginBottom: 12 }}>
          Property Price <span style={{ color: 'var(--gold)' }}>Estimator</span>
        </h1>
        <p style={{ color: 'var(--text-secondary)', fontSize: 16, maxWidth: 540 }}>
          Enter your property details below for an AI-generated market price estimate using our Gradient Boosting model.
        </p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: result ? '1fr 1fr' : '1fr', gap: 32, alignItems: 'start' }}>
        {/* Form */}
        <div style={{
          background: 'var(--surface)',
          border: '1px solid var(--border-subtle)',
          borderRadius: 'var(--radius-lg)',
          padding: 36,
          animation: 'fadeUp 0.5s ease 0.1s both',
        }}>
          <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 28, fontFamily: 'var(--font-display)' }}>
            Property Details
          </h2>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
            {/* Location */}
            <div style={{ gridColumn: '1 / -1' }}>
              <div style={{ height: 1, background: 'var(--border-subtle)', marginBottom: 20 }} />
              <div style={{ fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-muted)', marginBottom: 16 }}>Location</div>
            </div>

<InputField label="City / Municipality" required error={errors.city}>
  <input type="text" placeholder="e.g. Quezon City, Makati, Cebu City"
    value={form.city} onChange={e => update('city', e.target.value)}
    style={inputStyle(!!errors.city)}
    onFocus={e => e.target.style.borderColor = 'var(--gold)'}
    onBlur={e => e.target.style.borderColor = errors.city ? 'var(--error)' : 'var(--border-subtle)'}
  />
</InputField>

<InputField label="Province" required error={errors.province}>
  <input type="text" placeholder="e.g. Metro Manila, Cavite, Cebu"
    value={form.province} onChange={e => update('province', e.target.value)}
    style={inputStyle(!!errors.province)}
    onFocus={e => e.target.style.borderColor = 'var(--gold)'}
    onBlur={e => e.target.style.borderColor = errors.province ? 'var(--error)' : 'var(--border-subtle)'}
  />
</InputField>

<InputField label="Region" required error={errors.region}>
  <input type="text" placeholder="e.g. NCR, National Capital Region, Calabarzon"
    value={form.region} onChange={e => update('region', e.target.value)}
    style={inputStyle(!!errors.region)}
    onFocus={e => e.target.style.borderColor = 'var(--gold)'}
    onBlur={e => e.target.style.borderColor = errors.region ? 'var(--error)' : 'var(--border-subtle)'}
  />
</InputField>

            {/* Divider */}
            <div style={{ gridColumn: '1 / -1' }}>
              <div style={{ height: 1, background: 'var(--border-subtle)', marginBottom: 20, marginTop: 8 }} />
              <div style={{ fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-muted)', marginBottom: 16 }}>Property Specs</div>
            </div>

            <InputField label="Floor Area (sqm)" required error={errors.floor_area}>
              <input type="number" placeholder="e.g. 75" value={form.floor_area}
                onChange={e => update('floor_area', e.target.value)}
                style={inputStyle(!!errors.floor_area)}
                onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                onBlur={e => e.target.style.borderColor = errors.floor_area ? 'var(--error)' : 'var(--border-subtle)'}
                min="1"
              />
            </InputField>

            <InputField label="Land Area (sqm)" error={errors.land_area}>
              <input type="number" placeholder="Optional" value={form.land_area}
                onChange={e => update('land_area', e.target.value)}
                style={inputStyle(!!errors.land_area)}
                onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                onBlur={e => e.target.style.borderColor = errors.land_area ? 'var(--error)' : 'var(--border-subtle)'}
                min="1"
              />
            </InputField>

            <InputField label="Bedrooms" required error={errors.bedrooms}>
              <input type="number" placeholder="e.g. 3" value={form.bedrooms}
                onChange={e => update('bedrooms', e.target.value)}
                style={inputStyle(!!errors.bedrooms)}
                onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                onBlur={e => e.target.style.borderColor = errors.bedrooms ? 'var(--error)' : 'var(--border-subtle)'}
                min="1" max="20"
              />
            </InputField>

            <InputField label="Bathrooms" required error={errors.bathrooms}>
              <input type="number" placeholder="e.g. 2" value={form.bathrooms}
                onChange={e => update('bathrooms', e.target.value)}
                style={inputStyle(!!errors.bathrooms)}
                onFocus={e => e.target.style.borderColor = 'var(--gold)'}
                onBlur={e => e.target.style.borderColor = errors.bathrooms ? 'var(--error)' : 'var(--border-subtle)'}
                min="1" max="20"
              />
            </InputField>
          </div>

          {apiError && (
            <div style={{
              marginTop: 20, padding: '14px 18px',
              background: 'rgba(255,107,107,0.08)', border: '1px solid rgba(255,107,107,0.3)',
              borderRadius: 10, color: 'var(--error)', fontSize: 14,
            }}>
              ⚠ {apiError}
            </div>
          )}

          <div style={{ display: 'flex', gap: 12, marginTop: 28 }}>
            <button onClick={handleSubmit} disabled={loading} style={{
              flex: 1,
              background: loading ? 'rgba(201,168,76,0.4)' : 'linear-gradient(135deg, var(--gold), #b8943e)',
              border: 'none', borderRadius: 10,
              color: 'var(--navy)', padding: '14px 24px',
              fontSize: 16, fontFamily: 'var(--font-display)', fontWeight: 700,
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'all 0.2s',
            }}>
              {loading ? 'Analyzing...' : '🔍 Generate Forecast'}
            </button>
            <button onClick={handleReset} style={{
              background: 'transparent', border: '1px solid var(--border-subtle)',
              borderRadius: 10, color: 'var(--text-secondary)',
              padding: '14px 20px', cursor: 'pointer', fontSize: 14,
              transition: 'all 0.2s',
            }}
              onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--border)'}
              onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--border-subtle)'}
            >
              Reset
            </button>
          </div>

          <p style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 16, lineHeight: 1.5 }}>
            * Required fields. Price estimates carry a ±14.92% confidence margin based on the model's MAPE of 29.84%.
          </p>
        </div>

        {/* Result panel */}
        {result && (
          <div style={{ animation: 'fadeUp 0.4s ease' }}>
            {/* Main price card */}
            <div style={{
              background: `linear-gradient(135deg, var(--navy-mid), var(--navy-light))`,
              border: '1px solid var(--border)',
              borderRadius: 'var(--radius-lg)',
              padding: 36,
              marginBottom: 20,
              position: 'relative',
              overflow: 'hidden',
            }}>
              <div style={{
                position: 'absolute', top: -40, right: -40,
                width: 160, height: 160,
                background: 'radial-gradient(circle, rgba(201,168,76,0.12) 0%, transparent 70%)',
              }} />

              <div style={{ fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-muted)', marginBottom: 8 }}>
                Estimated Market Price
              </div>
              <div style={{
                fontSize: 'clamp(32px, 5vw, 52px)',
                fontFamily: 'var(--font-display)', fontWeight: 800,
                color: 'var(--gold)',
                lineHeight: 1.1, marginBottom: 8,
              }}>
                {formatPHP(result.predicted_price)}
              </div>
              <div style={{ fontSize: 14, color: 'var(--text-secondary)', marginBottom: 24 }}>
                Range: {formatPHP(result.price_low)} – {formatPHP(result.price_high)}
              </div>

              {/* Progress bar for confidence */}
              <div style={{ marginBottom: 24 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
                  <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>Confidence Range</span>
                  <span style={{ fontSize: 12, color: 'var(--teal)' }}>±14.92%</span>
                </div>
                <div style={{ height: 6, background: 'rgba(255,255,255,0.06)', borderRadius: 3 }}>
                  <div style={{
                    width: '70%', height: '100%',
                    background: 'linear-gradient(90deg, var(--teal), var(--gold))',
                    borderRadius: 3,
                  }} />
                </div>
              </div>

              {/* Property summary */}
              <div style={{
                display: 'grid', gridTemplateColumns: '1fr 1fr',
                gap: 12, paddingTop: 20,
                borderTop: '1px solid var(--border-subtle)',
              }}>
                {[
                  ['📍 Location', `${result.city}, ${result.province}`],
                  ['🗺 Region', result.region],
                  ['📐 Floor Area', `${result.floor_area} sqm`],
                  ['🛏 Bedrooms', result.bedrooms],
                  ['🚿 Bathrooms', result.bathrooms],
                  ['📊 Price/sqm', formatPHP(Math.round(result.predicted_price / result.floor_area))],
                ].map(([k, v]) => (
                  <div key={k}>
                    <div style={{ fontSize: 11, color: 'var(--text-muted)', marginBottom: 2 }}>{k}</div>
                    <div style={{ fontSize: 14, fontWeight: 500 }}>{v}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Model info */}
            <div style={{
              background: 'var(--surface)',
              border: '1px solid var(--border-subtle)',
              borderRadius: 'var(--radius)',
              padding: 20,
            }}>
              <div style={{ fontSize: 12, color: 'var(--text-muted)', marginBottom: 12, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
                Model Performance
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 12 }}>
                {[
                  { label: 'MAPE', value: '29.84%', note: 'Error rate' },
                  { label: 'CV', value: '2.09%', note: 'Stability' },
                  { label: 'Robustness', value: '7.21%', note: 'Degradation' },
                ].map(m => (
                  <div key={m.label} style={{ textAlign: 'center' }}>
                    <div style={{ fontSize: 20, fontFamily: 'var(--font-display)', fontWeight: 700, color: 'var(--teal)' }}>{m.value}</div>
                    <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{m.label}</div>
                  </div>
                ))}
              </div>
              <div style={{ marginTop: 16, padding: '10px 14px', background: 'rgba(255,255,255,0.03)', borderRadius: 8 }}>
                <p style={{ fontSize: 12, color: 'var(--text-muted)', lineHeight: 1.6 }}>
                  ⚠ This estimate is generated by a Gradient Boosting model and should be used for reference only. Please consult a licensed appraiser for formal property valuation.
                </p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
